def gen(rng, size):
    n = max(1, min(size, 700))
    target = list(range(1, n + 1))
    rng.shuffle(target)
    m = max(1, min(size, 700))
    arr = []
    for _ in range(m):
        if rng.random() < 0.7:
            arr.append(rng.choice(target))
        else:
            arr.append(rng.randint(2000000, 3000000))
    return [target, arr]

