class Solution:
    def minOperations(self, target, arr):
        pos = {v: i for i, v in enumerate(target)}
        seq = [pos[v] for v in arr if v in pos]
        n = len(seq)
        if n == 0:
            return len(target)
        dp = [1] * n
        for i in range(n):
            for j in range(i):
                if seq[j] < seq[i] and dp[j] + 1 > dp[i]:
                    dp[i] = dp[j] + 1
        return len(target) - max(dp)

