var minOperations = function(target, arr) {
    const pos = new Map();
    for (let i = 0; i < target.length; i++) pos.set(target[i], i);
    const seq = [];
    for (const v of arr) if (pos.has(v)) seq.push(pos.get(v));
    const tails = [];
    for (const x of seq) {
        let lo = 0, hi = tails.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (tails[mid] < x) lo = mid + 1; else hi = mid;
        }
        if (lo === tails.length) tails.push(x); else tails[lo] = x;
    }
    return target.length - tails.length;
};
